protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9 changed the default discriminator property from "Discriminator" to "$type".
        // Preserve "Discriminator" so existing 500K documents remain queryable and
        // direct SQL queries referencing c.Discriminator continue to work.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9 no longer embeds the discriminator in the JSON id property.
        // Preserve the old "Product|123" id format so existing documents are still
        // found by FindAsync / point-reads.
        entity.HasRootDiscriminatorInJsonId(true);
    });

    // Removed: HasIndex(p => p.Sku)
    // EF Core 9 Cosmos provider throws at startup for HasIndex calls.
    // Cosmos DB indexing is managed via the container's indexing policy
    // (Azure Portal, Bicep, or Terraform), not through EF Core.
}

